import time
from typing import Any, Dict, Optional

import jwt


def generate_jwt(user_id: int, role: str, secret_key: str, expires_in_seconds: int = 3600) -> str:
    now = int(time.time())
    payload: Dict[str, Any] = {
        "sub": str(user_id),
        "role": role,
        "iat": now,
        "exp": now + expires_in_seconds,
    }
    return jwt.encode(payload, secret_key, algorithm="HS256")


def decode_jwt(token: str, secret_key: str) -> Dict[str, Any]:
    return jwt.decode(token, secret_key, algorithms=["HS256"])


def generate_login_response(
    user_id: int,
    role: str,
    secret_key: str,
    expires_in_seconds: int = 3600,
    token_type: str = "Bearer",
) -> Dict[str, Any]:
    token = generate_jwt(user_id, role, secret_key, expires_in_seconds)
    return {
        "access_token": token,
        "token_type": token_type,
        "expires_in": expires_in_seconds,
        "user": {
            "id": user_id,
            "role": role,
        },
    }


